create database ai;

use ai;

CREATE TABLE properties (
    id INT AUTO_INCREMENT PRIMARY KEY,

    propertyId VARCHAR(50) UNIQUE NOT NULL,

    sellerName VARCHAR(255),

    propertyType VARCHAR(100),
    propertySubtype VARCHAR(100),
    unitType VARCHAR(50),

    wing VARCHAR(20),
    unitNo VARCHAR(20),

    furnishing VARCHAR(100),

    parkingType VARCHAR(50),
    parkingQty INT DEFAULT 0,

    city VARCHAR(100),
    location VARCHAR(150),
    society VARCHAR(255),

    floor VARCHAR(50),
    totalFloors VARCHAR(50),

    carpetArea DECIMAL(10,2),
    builtupArea DECIMAL(10,2),

    budget BIGINT,

    address TEXT,

    status VARCHAR(50),
    leadSource VARCHAR(100),

    possessionMonth INT,
    possessionYear INT,

    purchaseMonth INT,
    purchaseYear INT,

    sellingRights VARCHAR(100),

    description TEXT,

    isPublic BOOLEAN DEFAULT TRUE,

    publicationDate DATETIME,
    createdAt DATETIME DEFAULT CURRENT_TIMESTAMP,
    updatedAt DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,

    amenities TEXT,
    furnishingItems TEXT,

    photoCount INT DEFAULT 0
);


